CREATE TABLE notification_templates(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),key text NOT NULL,locale text NOT NULL,channel text NOT NULL CHECK(channel IN('email','sms','push','in_app')),topic text NOT NULL CHECK(topic IN('appointment','service','document','passport','security','marketing')),subject text,body text NOT NULL,active boolean NOT NULL DEFAULT true,created_at timestamptz NOT NULL,UNIQUE(tenant_id,organization_id,key,locale,channel));
CREATE TABLE notification_preferences(tenant_id uuid NOT NULL REFERENCES tenants(id),customer_id uuid NOT NULL REFERENCES customers(id),topic text NOT NULL CHECK(topic IN('appointment','service','document','passport','security','marketing')),enabled_channels text[] NOT NULL,marketing_consent boolean NOT NULL DEFAULT false,locale text NOT NULL,timezone text NOT NULL,updated_at timestamptz NOT NULL,PRIMARY KEY(tenant_id,customer_id,topic));
CREATE TABLE notifications(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),customer_id uuid NOT NULL REFERENCES customers(id),template_id uuid NOT NULL REFERENCES notification_templates(id),channel text NOT NULL CHECK(channel IN('email','sms','push','in_app')),topic text NOT NULL CHECK(topic IN('appointment','service','document','passport','security','marketing')),recipient text,subject text,body text NOT NULL,brand_name text NOT NULL,brand_primary_color char(7) NOT NULL,idempotency_key text NOT NULL,status text NOT NULL CHECK(status IN('queued','sent','failed','cancelled')),attempts integer NOT NULL DEFAULT 0 CHECK(attempts>=0),provider_message_id text,last_error text,created_at timestamptz NOT NULL,sent_at timestamptz,UNIQUE(tenant_id,idempotency_key,channel));
CREATE INDEX notifications_customer_idx ON notifications(tenant_id,customer_id,created_at DESC);
CREATE INDEX notifications_dispatch_idx ON notifications(tenant_id,status,created_at) WHERE status IN('queued','failed');
DO $$ DECLARE n text;BEGIN FOREACH n IN ARRAY ARRAY['notification_templates','notification_preferences','notifications'] LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY',n);EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY',n);EXECUTE format('CREATE POLICY tenant_isolation ON %I USING (tenant_id=current_setting(''app.tenant_id'',true)::uuid) WITH CHECK (tenant_id=current_setting(''app.tenant_id'',true)::uuid)',n);END LOOP;END $$;
